import torch
import torch.nn as nn
import torch.distributed as dist


class _AllGather(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input):
        world_size = dist.get_world_size()
        if world_size == 1:
            return input
        gathered = [torch.zeros_like(input) for _ in range(world_size)]
        dist.all_gather(gathered, input)
        return torch.cat(gathered, dim=-1)

    @staticmethod
    def backward(ctx, grad_output):
        world_size = dist.get_world_size()
        if world_size == 1:
            return grad_output
        rank = dist.get_rank()
        chunk_size = grad_output.shape[-1] // world_size
        return grad_output[..., rank * chunk_size : (rank + 1) * chunk_size].contiguous()


class _AllReduce(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input):
        world_size = dist.get_world_size()
        if world_size == 1:
            return input
        output = input.clone()
        dist.all_reduce(output, op=dist.ReduceOp.SUM)
        return output

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output


class ColumnParallelLinear(nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features

        world_size = dist.get_world_size()
        rank = dist.get_rank()

        self.out_features_per_rank = out_features // world_size

        # master_weight shape: (out_features, in_features)
        weight_chunks = master_weight.chunk(world_size, dim=0)
        self.weight = nn.Parameter(weight_chunks[rank].contiguous().clone())

        if bias:
            self.bias = nn.Parameter(torch.zeros(self.out_features_per_rank))
        else:
            self.bias = None

    def forward(self, x):
        local_output = torch.nn.functional.linear(x, self.weight, self.bias)
        return _AllGather.apply(local_output)


class RowParallelLinear(nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features

        world_size = dist.get_world_size()
        rank = dist.get_rank()

        self.in_features_per_rank = in_features // world_size

        # master_weight shape: (out_features, in_features)
        weight_chunks = master_weight.chunk(world_size, dim=1)
        self.weight = nn.Parameter(weight_chunks[rank].contiguous().clone())

        if bias:
            self.bias = nn.Parameter(torch.zeros(out_features))
        else:
            self.bias = None

    def forward(self, x):
        local_output = torch.nn.functional.linear(x, self.weight)
        output = _AllReduce.apply(local_output)
        if self.bias is not None:
            output = output + self.bias
        return output

